module calendar(
    input CLK,
    input RST,
    output [5:0] Hours,
    output [5:0] Mins,
    output [5:0] Secs
);

reg [5:0] sec_reg, min_reg, hour_reg;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        sec_reg <= 6'b000000;
        min_reg <= 6'b000000;
        hour_reg <= 6'b000000;
    end
    else begin
        if (sec_reg == 6'b111011) begin
            sec_reg <= 6'b000000;
            if (min_reg == 6'b111011) begin
                min_reg <= 6'b000000;
                if (hour_reg == 6'b110011) begin
                    hour_reg <= 6'b000000;
                end
                else begin
                    hour_reg <= hour_reg + 1;
                end
            end
            else begin
                min_reg <= min_reg + 1;
            end
        end
        else begin
            sec_reg <= sec_reg + 1;
        end
    end
end

assign Secs = sec_reg;
assign Mins = min_reg;
assign Hours = hour_reg;

endmodule
